class ExamRoom {
public:
    ExamRoom(int n) : n(n), seats(n + 1, false) {}

    int seat() {
        if (!last) {
            last = 0;
            return 0;
        }
        int maxDist = 0, idx = 0;
        for (int i = 0; i < n; ++i) {
            if (seats[i]) continue;
            int dist = i;
            if (i > 0 && seats[i - 1]) dist = (i - (i - 1)) / 2;
            if (i < n - 1 && seats[i + 1]) dist = (i + 1 - i) / 2;
            if (dist > maxDist) {
                maxDist = dist;
                idx = i;
            }
        }
        seats[idx] = true;
        last = idx;
        return idx;
    }

    void leave(int p) {
        seats[p] = false;
        last = p;
    }

private:
    int n;
    vector<bool> seats;
    int last = -1;
};
```
